// carrying the Run() error.
func runBlockedHeartbeatLoopWithRuntime(t *testing.T, store *bead.Store, heartbeatInterval time.Duration, runtime ExecuteBeadLoopRuntime) (func(), <-chan error) {
	t.Helper()

