func (s *staleReadyStore) ReadyExecution() ([]bead.Bead, error) {
	if atomic.AddInt32(&s.readyCalls, 1) <= 2 {
		out := make([]bead.Bead, len(s.staleReady))
		copy(out, s.staleReady)
		return out, nil
	}
	return s.Store.ReadyExecution()
}

