func withHeartbeat(t *testing.T, interval, ttl time.Duration) {
	t.Helper()
	origInterval := HeartbeatInterval
	origTTL := HeartbeatTTL
	HeartbeatInterval = interval
	HeartbeatTTL = ttl
	t.Cleanup(func() {
		HeartbeatInterval = origInterval
		HeartbeatTTL = origTTL
	})
}

